import{_ as a,c as i,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"Preguntas Frecuentes y Optimización: Solución de Problemas, Comandos CLI, Ajuste de Rendimiento | Tutorial de Clawdbot","description":"Resuelve problemas comunes al usar Clawdbot, domina la referencia completa de comandos CLI y aprende técnicas de optimización de rendimiento para mejorar la estabilidad del sistema y la velocidad de respuesta.","frontmatter":{"title":"Preguntas Frecuentes y Optimización: Solución de Problemas, Comandos CLI, Ajuste de Rendimiento | Tutorial de Clawdbot","sidebarTitle":"¿Qué hacer si hay problemas","subtitle":"Preguntas Frecuentes y Optimización","description":"Resuelve problemas comunes al usar Clawdbot, domina la referencia completa de comandos CLI y aprende técnicas de optimización de rendimiento para mejorar la estabilidad del sistema y la velocidad de respuesta.","tags":["Preguntas Frecuentes","Solución de Problemas","CLI","Optimización de Rendimiento"],"order":300},"headers":[],"relativePath":"es/moltbot/moltbot/faq/index.md","filePath":"es/moltbot/moltbot/faq/index.md"}'),r={name:"es/moltbot/moltbot/faq/index.md"};function s(t,e,l,d,c,m){return o(),i("div",null,[...e[0]||(e[0]=[n('<h1 id="preguntas-frecuentes-y-optimizacion" tabindex="-1">Preguntas Frecuentes y Optimización <a class="header-anchor" href="#preguntas-frecuentes-y-optimizacion" aria-label="Permalink to &quot;Preguntas Frecuentes y Optimización&quot;">​</a></h1><p>Este capítulo te ayuda a resolver varios problemas al usar Clawdbot, dominar los métodos completos de operación de línea de comandos y aprender cómo optimizar el rendimiento del sistema.</p><div class="info custom-block"><p class="custom-block-title">Recomendación de Orden de Aprendizaje</p><p>Se recomienda leer este capítulo en el siguiente orden:</p><ol><li>Primero aprende <strong><a href="./cli-commands/">Referencia de Comandos CLI</a></strong> —— Domina las operaciones básicas y herramientas de depuración</li><li>Luego aprende <strong><a href="./troubleshooting/">Solución de Problemas</a></strong> —— Para localizar y resolver problemas rápidamente cuando ocurren</li><li>Finalmente aprende <strong><a href="./performance-optimization/">Optimización de Rendimiento</a></strong> —— Para mejorar la eficiencia del sistema</li></ol></div><h2 id="navegacion-de-subpaginas" tabindex="-1">Navegación de Subpáginas <a class="header-anchor" href="#navegacion-de-subpaginas" aria-label="Permalink to &quot;Navegación de Subpáginas&quot;">​</a></h2><h3 id="solucion-de-problemas" tabindex="-1"><a href="./troubleshooting/">Solución de Problemas</a> <a class="header-anchor" href="#solucion-de-problemas" aria-label="Permalink to &quot;[Solución de Problemas](./troubleshooting/)&quot;">​</a></h3><p>Una guía completa de solución de problemas para problemas comunes, que cubre:</p><ul><li>Fallos de inicio de Gateway</li><li>Problemas de conexión de canales (WhatsApp, Telegram, Slack, etc.)</li><li>Errores de autenticación y problemas de permisos</li><li>Fallos en la invocación de herramientas</li><li>Excepciones en la gestión de sesiones</li></ul><p><strong>Cuándo usar</strong>: Cuando encuentras problemas específicos y necesitas solucionarlos y resolverlos rápidamente.</p><hr><h3 id="referencia-de-comandos-cli" tabindex="-1"><a href="./cli-commands/">Referencia de Comandos CLI</a> <a class="header-anchor" href="#referencia-de-comandos-cli" aria-label="Permalink to &quot;[Referencia de Comandos CLI](./cli-commands/)&quot;">​</a></h3><p>Lista completa de comandos e instrucciones de uso, que incluye:</p><ul><li>Comandos de control de Gateway (inicio, reinicio, estado)</li><li>Comandos de interacción con Agent</li><li>Gestión y configuración de modelos</li><li>Gestión de canales (inicio de sesión, estado, cierre de sesión)</li><li>Gestión de sesiones (lista, restablecimiento, eliminación, compresión)</li><li>Gestión de nodos (lista, invocación, emparejamiento)</li><li>Gestión de habilidades y asistente de configuración</li></ul><p><strong>Cuándo usar</strong>: Cuando necesitas encontrar rápidamente el uso y parámetros de un comando, o aprender la funcionalidad completa de CLI.</p><hr><h3 id="optimizacion-de-rendimiento" tabindex="-1"><a href="./performance-optimization/">Optimización de Rendimiento</a> <a class="header-anchor" href="#optimizacion-de-rendimiento" aria-label="Permalink to &quot;[Optimización de Rendimiento](./performance-optimization/)&quot;">​</a></h3><p>Técnicas de optimización para mejorar el rendimiento y la velocidad de respuesta de Gateway, que cubre:</p><ul><li>Caché de Prompts (Prompt Caching) para reducir costos</li><li>Poda de Sesiones (Session Pruning) para reducir contexto</li><li>Control de concurrencia y gestión de recursos</li><li>Optimización de memoria y recolección de basura</li><li>Ajuste de niveles de registro</li></ul><p><strong>Cuándo usar</strong>: Cuando el sistema se ejecuta lentamente, el uso de recursos es alto, o deseas mejorar la experiencia del usuario.</p><h2 id="requisitos-previos" tabindex="-1">Requisitos Previos <a class="header-anchor" href="#requisitos-previos" aria-label="Permalink to &quot;Requisitos Previos&quot;">​</a></h2><p>Antes de aprender este capítulo, se recomienda que hayas completado:</p><ul><li>✅ <strong><a href="./../../start/getting-started/">Inicio Rápido</a></strong> —— Comprender los procesos básicos de instalación y configuración</li><li>✅ <strong><a href="./../../start/gateway-startup/">Iniciar Gateway</a></strong> —— Saber cómo iniciar y gestionar Gateway</li></ul><h2 id="proximos-pasos" tabindex="-1">Próximos Pasos <a class="header-anchor" href="#proximos-pasos" aria-label="Permalink to &quot;Próximos Pasos&quot;">​</a></h2><p>Después de completar este capítulo, puedes continuar aprendiendo:</p><ul><li><strong><a href="./../../appendix/config-reference/">Referencia Completa de Configuración</a></strong> —— Comprender en profundidad las explicaciones detalladas de todas las opciones de configuración</li><li><strong><a href="./../../appendix/deployment/">Opciones de Despliegue</a></strong> —— Aprender cómo desplegar Clawdbot en diferentes plataformas</li><li><strong><a href="./../../appendix/development/">Guía de Desarrollo</a></strong> —— Comprender el desarrollo de complementos y el proceso de contribución</li></ul>',24)])])}const b=a(r,[["render",s]]);export{u as __pageData,b as default};
